import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  LineChart,
  Line,
  CartesianGrid,
  XAxis,
  YAxis,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import "./PriceAnalytics.css";

const API_URL = "http://localhost:7000/api/prices/trends";

export default function PriceAnalytics() {
  const [data, setData] = useState([]);
  const [type, setType] = useState("product");
  const [range, setRange] = useState("monthly");
  const [filter, setFilter] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchTrends = async () => {
    try {
      setLoading(true);
      const res = await axios.get(API_URL, {
        params: { type, range, filter },
      });
      setData(res.data || []);
    } catch (error) {
      console.error("Error fetching trends:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTrends();
  }, [type, range]);

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price Trends Analysis</h2>

      {/* Filter Box */}
      <div className="filter-box">
        <label>Type:</label>
        <select value={type} onChange={(e) => setType(e.target.value)}>
          <option value="product">Product</option>
          <option value="category">Category</option>
        </select>

        <label>Range:</label>
        <select value={range} onChange={(e) => setRange(e.target.value)}>
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
        </select>

        <input
          type="text"
          placeholder={`Filter by ${type}`}
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        />
        <button onClick={fetchTrends}>Apply Filter</button>
      </div>

      {loading ? (
        <p style={{ textAlign: "center" }}>Loading trends...</p>
      ) : (
        <>
          {data.length > 0 ? (
            data.map((item) => (
              <div key={item._id} className="chart-section">
                <h3>
                  {type === "category" ? "Category" : "Product"}:{" "}
                  <span style={{ color: "#007bff" }}>{item._id}</span>
                </h3>
                <ResponsiveContainer width="100%" height={350}>
                  <LineChart data={item.prices}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" />
                    <YAxis />
                    <Tooltip />
                    <Legend />
                    <Line
                      type="monotone"
                      dataKey="avgPrice"
                      stroke="#82ca9d"
                      name="Avg Price (₹)"
                    />
                    <Line
                      type="monotone"
                      dataKey="difference"
                      stroke="#ff7300"
                      name="Price Difference"
                    />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            ))
          ) : (
            <p style={{ textAlign: "center", color: "#888" }}>
              No trend data found.
            </p>
          )}
        </>
      )}
    </div>
  );
}
